@page "/Account/Login"
@using Microsoft.AspNetCore.Identity
@using sv_bf46d21e7ec44fa49fe1afc4946be704.Data
@inject SignInManager<ApplicationUser> SignInManager
@inject NavigationManager Navigation

<PageTitle>Login</PageTitle>

<div class="row justify-content-center mt-5">
    <div class="col-md-4">
        <h2>Login</h2>
        @if (!string.IsNullOrEmpty(errorMessage))
        {
            <div class="alert alert-danger">@errorMessage</div>
        }
        <form method="post" @formname="login">
            <AntiforgeryToken />
            <div class="mb-3">
                <label for="email" class="form-label">Email</label>
                <input type="email" class="form-control" id="email" name="Email"
                       @bind="Input.Email" required />
            </div>
            <div class="mb-3">
                <label for="password" class="form-label">Password</label>
                <input type="password" class="form-control" id="password" name="Password"
                       @bind="Input.Password" required />
            </div>
            <button type="submit" class="btn btn-primary w-100">Sign in</button>
        </form>
    </div>
</div>

@code {
    private string? errorMessage;

    [SupplyParameterFromForm]
    private LoginModel Input { get; set; } = new();

    [SupplyParameterFromQuery]
    private string? ReturnUrl { get; set; }

    protected override async Task OnInitializedAsync()
    {
        if (HttpMethods.IsPost(HttpContextAccessor.HttpContext!.Request.Method))
        {
            var result = await SignInManager.PasswordSignInAsync(
                Input.Email, Input.Password, isPersistent: false, lockoutOnFailure: false);

            if (result.Succeeded)
            {
                Navigation.NavigateTo(ReturnUrl ?? "/", forceLoad: true);
                return;
            }

            errorMessage = "Invalid email or password.";
        }
    }

    [CascadingParameter]
    private HttpContext HttpContextAccessor { get; set; } = default!;

    private sealed class LoginModel
    {
        public string Email { get; set; } = string.Empty;
        public string Password { get; set; } = string.Empty;
    }
}

@page "/Account/Logout"
@using Microsoft.AspNetCore.Identity
@using sv_bf46d21e7ec44fa49fe1afc4946be704.Data
@inject SignInManager<ApplicationUser> SignInManager
@inject NavigationManager Navigation

@code {
    [CascadingParameter]
    private HttpContext HttpContextAccessor { get; set; } = default!;

    protected override async Task OnInitializedAsync()
    {
        if (HttpMethods.IsPost(HttpContextAccessor.Request.Method))
        {
            await SignInManager.SignOutAsync();
            Navigation.NavigateTo("/", forceLoad: true);
        }
    }
}

<PageTitle>Logout</PageTitle>

<div class="row justify-content-center mt-5">
    <div class="col-md-4 text-center">
        <h2>Sign out</h2>
        <form method="post" @formname="logout">
            <AntiforgeryToken />
            <button type="submit" class="btn btn-outline-danger">Click here to sign out</button>
        </form>
    </div>
</div>

@page "/admin/users"
@rendermode InteractiveServer
@using Microsoft.AspNetCore.Authorization
@using Microsoft.AspNetCore.Identity
@using sv_bf46d21e7ec44fa49fe1afc4946be704.Data
@attribute [Authorize(Roles = "Admin")]
@inject UserManager<ApplicationUser> UserManager

<PageTitle>User Management</PageTitle>

<h1>User Management</h1>
<p>All registered users and their assigned roles.</p>

@if (users is null)
{
    <p><em>Loading…</em></p>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Name</th>
                <th>Email</th>
                <th>Roles</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var (user, roles) in users)
            {
                <tr>
                    <td>@user.FullName</td>
                    <td>@user.Email</td>
                    <td>@string.Join(", ", roles)</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<(ApplicationUser User, IList<string> Roles)>? users;

    protected override async Task OnInitializedAsync()
    {
        var allUsers = UserManager.Users.ToList();
        var result = new List<(ApplicationUser, IList<string>)>();
        foreach (var user in allUsers)
        {
            var roles = await UserManager.GetRolesAsync(user);
            result.Add((user, roles));
        }
        users = result;
    }
}

